import{_ as e,o as d,c as a,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Page Settings","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Page/page-settings.md","filePath":"ps/Page/page-settings.md","lastUpdated":1781962217000}'),r={name:"ps/Page/page-settings.md"};function n(i,t,l,g,s,c){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="page-settings" tabindex="-1">Page Settings <a class="header-anchor" href="#page-settings" aria-label="Permalink to &quot;Page Settings&quot;">​</a></h1><p>Page settings د site display، upload page defaults، background images او admin panel appearance کنټرولوي.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>موخه</th></tr></thead><tbody><tr><td>Site title</td><td>هغه title چې browser tab کې ښکاري.</td></tr><tr><td>Site icon</td><td>هغه کوچنی icon چې browser tab کې ښکاري.</td></tr><tr><td>ImgBed name</td><td>په frontend pages کې ښکاره کېدونکی نوم.</td></tr><tr><td>ImgBed logo</td><td>په frontend pages کې ښکاره کېدونکی logo image.</td></tr><tr><td>Logo link</td><td>هغه URL چې د logo یا avatar په کلیک پرانیستل کېږي.</td></tr><tr><td>Background switch interval</td><td>د څو backgrounds د rotation interval، په milliseconds کې. <code>60000</code> یعنې 60 seconds.</td></tr><tr><td>Background opacity</td><td>د background image opacity له <code>0</code> تر <code>1</code> پورې. ټیټ values روښانه وي.</td></tr><tr><td>Default URL prefix</td><td>د image links د جوړولو پر وخت کارېدونکی prefix. تش وي نو د اوسني site domain کارېږي.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>موخه</th></tr></thead><tbody><tr><td>Announcement</td><td>هغه announcement چې د upload page په سر کې ښکاري. HTML supported دی.</td></tr><tr><td>Default upload channel</td><td>upload channel چې په upload page کې default selected وي. Smart Dispatch هم ټاکلای شئ.</td></tr><tr><td>Default upload directory</td><td>default upload directory، لکه <code>/user/</code>. تش یا <code>/</code> یعنې root.</td></tr><tr><td>Default naming method</td><td>له upload وروسته د default filename generation strategy. لاندې یې وګورئ.</td></tr><tr><td>Convert to WebP by default</td><td>images له upload مخکې WebP ته بدلوي.</td></tr><tr><td>Enable compression by default</td><td>images له upload مخکې په browser کې locally compress کوي.</td></tr><tr><td>Default compression threshold</td><td>کله چې image له دې size واوړي، په اتومات ډول compress کېږي، په MB کې.</td></tr><tr><td>Default target size</td><td>له compression وروسته target file size، په MB کې.</td></tr><tr><td>Login page background</td><td>د user login page background image.</td></tr><tr><td>Upload page background</td><td>د upload page background image.</td></tr><tr><td>Footer portal link</td><td>هغه URL چې footer portal button یې پرانیزي.</td></tr><tr><td>Hide footer</td><td>که enabled وي، frontend footer پټوي.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>موخه</th></tr></thead><tbody><tr><td>Admin login background</td><td>د admin login page background image.</td></tr><tr><td>Admin background</td><td>د admin pages background image. یو image URL یا څو URLs وکاروئ.</td></tr><tr><td>Image loading mode</td><td>د admin file list preview loading mode. Original اصلي images load کوي. Smart loading د public images لپاره thumbnails او د restricted images لپاره originals ته ترجیح ورکوي.</td></tr><tr><td>Thumbnail source</td><td>د thumbnails جوړولو service: wsrv.nl، Cloudflare Image Resizing، یا WordPress Photon. Cloudflare Image Resizing باید په Cloudflare کې مخکې enabled وي.</td></tr><tr><td>Live2D widget</td><td>په admin panel کې Live2D character ښيي.</td></tr><tr><td>Firework click effect</td><td>د page کلیک پر وخت firework effect ښيي.</td></tr><tr><td>Star cursor trail</td><td>د mouse movement پر وخت star trail ښيي.</td></tr></tbody></table><h2 id="د-background-image-formats" tabindex="-1">د Background Image Formats <a class="header-anchor" href="#د-background-image-formats" aria-label="Permalink to &quot;د Background Image Formats&quot;">​</a></h2><p>Login page background، upload page background او admin login background دا formats ملاتړ کوي:</p><table tabindex="0"><thead><tr><th>Value</th><th>اغېز</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Bing wallpaper rotation کاروي.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>څو images rotate کوي.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>یو background image کاروي.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>د random image API link کاروي. خپل Random Image API په Other Settings کې تنظیمولای شئ، بیا generated random image link دلته د single-background entry په توګه paste کړئ.</td></tr></tbody></table><p>admin background د image URLs ملاتړ کوي. څو URLs د page د prompt له مخې په English commas جلا کېدای شي. تش وي نو default background کارېږي.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>Time-random prefix + original filename، لکه <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>یوازې time-random prefix او extension، لکه <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>original filename ساتي، لکه <code>cat.png</code>. که duplicate وي، ImgBed <code>(1)</code>، <code>(2)</code> او داسې نور اضافه کوي.</td></tr><tr><td>Short link</td><td>8-character short ID او extension کاروي، لکه <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const u=e(r,[["render",n]]);export{p as __pageData,u as default};
